import glob

def find_files(pattern: str, recursive: bool = False) -> list:
    """根据通配符模式查找文件，支持递归"""
    return glob.glob(pattern, recursive=recursive)

# 使用示例
if __name__ == '__main__':
    txt_files = find_files('*.txt')
    all_py = find_files('**/*.py', recursive=True)
    print(txt_files, all_py)
